{
  "name": "Agent测试模板",
  "description": "用于测试Agent修改功能的模板",
  "template_content": "# {{report_title}}\n\n## 基本信息\n- **项目名称**: {{project_name}}\n- **时间范围**: {{time_range}}\n- **状态**: {{status}}\n\n## 数据概览\n当前记录数: {{record_count}}\n\n## 分析结果\n{{analysis_content}}",
  "metadata": {
    "variables": [
      {
        "name": "report_title",
        "type": "string",
        "source": "user_input",
        "required": true,
        "description": "报告标题",
        "default": "测试报告",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入报告标题"
        }
      },
      {
        "name": "project_name",
        "type": "string",
        "source": "user_input",
        "required": true,
        "description": "项目名称",
        "default": "测试项目",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入项目名称"
        }
      },
      {
        "name": "time_range",
        "type": "string",
        "source": "user_input",
        "required": true,
        "description": "时间范围",
        "default": "2024-01-01 至 2024-03-31",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入时间范围"
        }
      },
      {
        "name": "status",
        "type": "string",
        "source": "user_input",
        "required": false,
        "description": "状态",
        "default": "进行中",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入状态"
        }
      },
      {
        "name": "record_count",
        "type": "number",
        "source": "constant",
        "required": false,
        "description": "记录数",
        "value": 100
      },
      {
        "name": "analysis_content",
        "type": "string",
        "source": "constant",
        "required": false,
        "description": "分析内容",
        "value": "初步分析表明项目进展顺利。"
      }
    ]
  }
}

{
  "template_id": "{{template_id}}",
  "inputs": {
    "report_title": "2024年度项目测试报告",
    "project_name": "Alpha项目",
    "time_range": "2024-01-01 至 2024-12-31",
    "status": "进行中"
  }
}

{
  "name": "微网格分析报告模板",
  "description": "包含SQL数据源的微网格报告模板",
  "template_content": "# 微网格分析报告\n\n## 一、基本信息\n- **微网格ID**: {{wgid}}\n- **微网格名称**: {{grid_name}}\n- **分析周期**: {{analysis_period}}\n\n## 二、概况统计\n- 总得分: {{overview.wgid_score}}\n- 问题总数: {{overview.problem_count}}\n- 工程站点数: {{overview.plan_count}}\n\n## 三、指标评分\n{% for item in index_scores %}\n- **{{item[\"index\"]}}**: {{item[\"values\"]}} (得分: {{item.index_score}})\n{% endfor %}",
  "metadata": {
    "variables": [
      {
        "name": "wgid",
        "type": "string",
        "source": "user_input",
        "required": true,
        "description": "微网格ID",
        "default": "ZQGY0174",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入微网格ID"
        }
      },
      {
        "name": "grid_name",
        "type": "string",
        "source": "user_input",
        "required": false,
        "description": "微网格名称",
        "default": "测试微网格",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入微网格名称"
        }
      },
      {
        "name": "analysis_period",
        "type": "string",
        "source": "user_input",
        "required": false,
        "description": "分析周期",
        "default": "2024年第一季度",
        "ui_config": {
          "input_type": "text",
          "placeholder": "请输入分析周期"
        }
      },
      {
        "name": "overview",
        "type": "object",
        "source": "sql",
        "required": false,
        "description": "微网格概况数据",
        "default": {},
        "dependencies": ["wgid"],
        "sql_config": {
          "connection": "test_db_connection",
          "query": "SELECT wgid_score, problem_count, plan_count FROM microgrid.micro_grid_overview_w WHERE wgid = '{{wgid}}' LIMIT 1",
          "parameters": ["wgid"],
          "timeout": 10,
          "result_mode": "first_row"
        }
      },
      {
        "name": "index_scores",
        "type": "array",
        "source": "sql",
        "required": false,
        "description": "指标评分数据",
        "default": [],
        "dependencies": ["wgid"],
        "sql_config": {
          "connection": "test_db_connection",
          "query": "SELECT \"index\" AS index_name, \"values\", index_score FROM microgrid.micro_grid_index_score_w WHERE wgid = '{{wgid}}'",
          "parameters": ["wgid"],
          "timeout": 10,
          "result_mode": "all_rows"
        }
      }
    ]
  }
}
